namespace sv_2ebcc96db8c84bb5bba37daa202a81da.Services;

public enum ThemeMode
{
    Light,
    Dark,
    System
}

/// <summary>
/// Scoped service (one instance per circuit) that holds theme state
/// and notifies all subscribers when it changes.
/// </summary>
public sealed class ThemeService
{
    private ThemeMode _theme = ThemeMode.System;
    private string _accentColor = "#0d6efd";

    public ThemeMode Theme
    {
        get => _theme;
        set
        {
            if (_theme == value) return;
            _theme = value;
            NotifyChanged();
        }
    }

    public string AccentColor
    {
        get => _accentColor;
        set
        {
            if (_accentColor == value) return;
            _accentColor = value;
            NotifyChanged();
        }
    }

    public event Action? OnChange;

    private void NotifyChanged() => OnChange?.Invoke();
}

@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<span class="theme-indicator" title="Current theme">
    @switch (ThemeService.Theme)
    {
        case ThemeMode.Light:
            <span>☀️ Light</span>
            break;
        case ThemeMode.Dark:
            <span>🌙 Dark</span>
            break;
        case ThemeMode.System:
            <span>💻 System</span>
            break;
    }
    <span class="accent-dot" style="background-color: @ThemeService.AccentColor;"></span>
</span>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        ThemeService.OnChange -= StateHasChanged;
    }
}

@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<div class="theme-toggle">
    <button class="btn btn-sm @ButtonClass" @onclick="CycleTheme" title="Toggle theme">
        @Icon
    </button>
</div>

@code {
    private string Icon => ThemeService.Theme switch
    {
        ThemeMode.Light => "☀️",
        ThemeMode.Dark => "🌙",
        _ => "💻"
    };

    private string ButtonClass => ThemeService.Theme switch
    {
        ThemeMode.Light => "btn-outline-warning",
        ThemeMode.Dark => "btn-outline-info",
        _ => "btn-outline-secondary"
    };

    private void CycleTheme()
    {
        ThemeService.Theme = ThemeService.Theme switch
        {
            ThemeMode.Light => ThemeMode.Dark,
            ThemeMode.Dark => ThemeMode.System,
            _ => ThemeMode.Light
        };
    }

    protected override void OnInitialized()
    {
        ThemeService.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        ThemeService.OnChange -= StateHasChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-3" style="max-width: 400px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>
        <div class="btn-group mb-3" role="group">
            @foreach (var mode in Enum.GetValues<ThemeMode>())
            {
                <button type="button"
                        class="btn @(ThemeService.Theme == mode ? "btn-primary" : "btn-outline-primary")"
                        @onclick="() => ThemeService.Theme = mode">
                    @mode
                </button>
            }
        </div>

        <h5 class="card-title">Accent Color</h5>
        <input type="color"
               class="form-control form-control-color mb-3"
               value="@ThemeService.AccentColor"
               @onchange="OnAccentColorChanged" />

        <div class="mt-3 p-3 border rounded"
             style="border-color: @ThemeService.AccentColor !important;">
            <strong>Preview:</strong> Theme is <em>@ThemeService.Theme</em>,
            accent is <span style="color: @ThemeService.AccentColor;">@ThemeService.AccentColor</span>
        </div>
    </div>
</div>

@code {
    private void OnAccentColorChanged(ChangeEventArgs e)
    {
        ThemeService.AccentColor = e.Value?.ToString() ?? "#0d6efd";
    }

    protected override void OnInitialized()
    {
        ThemeService.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        ThemeService.OnChange -= StateHasChanged;
    }
}

