@page "/settings"
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-3" style="max-width: 400px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>
        <div class="btn-group mb-3" role="group">
            @foreach (var mode in Enum.GetValues<ThemeMode>())
            {
                <button type="button"
                        class="btn @(ThemeService.Theme == mode ? "btn-primary" : "btn-outline-primary")"
                        @onclick="() => ThemeService.Theme = mode">
                    @mode
                </button>
            }
        </div>

        <h5 class="card-title">Accent Color</h5>
        <input type="color"
               class="form-control form-control-color mb-3"
               value="@ThemeService.AccentColor"
               @onchange="OnAccentColorChanged" />

        <div class="mt-3 p-3 border rounded"
             style="border-color: @ThemeService.AccentColor !important;">
            <strong>Preview:</strong> Theme is <em>@ThemeService.Theme</em>,
            accent is <span style="color: @ThemeService.AccentColor;">@ThemeService.AccentColor</span>
        </div>
    </div>
</div>

@code {
    private void OnAccentColorChanged(ChangeEventArgs e)
    {
        ThemeService.AccentColor = e.Value?.ToString() ?? "#0d6efd";
    }

    protected override void OnInitialized()
    {
        ThemeService.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        ThemeService.OnChange -= StateHasChanged;
    }
}

